# This module contains the logic for the checkers board

class Board:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        positions = [(0, 1), (0, 3), (0, 5), (0, 7),
                    (1, 0), (1, 2), (1, 4), (1, 6),
                    (2, 1), (2, 3), (2, 5), (2, 7),
                    (5, 0), (5, 2), (5, 4), (5, 6),
                    (6, 1), (6, 3), (6, 5), (6, 7),
                    (7, 0), (7, 2), (7, 4), (7, 6)]
        for row, col in positions:
            self.board[row][col] = 'B'  # Black pieces
        positions = [(3, 1), (3, 3), (3, 5), (3, 7),
                    (4, 0), (4, 2), (4, 4), (4, 6)]
        for row, col in positions:
            self.board[row][col] = 'W'  # White pieces

    def display(self):
        print("     A B C D E F G H")
        for i in range(8):
            print(f"   {i + 1} |", end="")
            for j in range(8):
                print(self.board[i][j], "|", end=" ")
            print()

    def move_piece(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos
        if self.board[row_from][col_from] == ' ':
            raise ValueError("No piece at the specified position.")
        if self.board[row_to][col_to] != ' ':
            raise ValueError("Position already occupied.")

        # Move piece logic here (simplified for now)
        self.board[row_to][col_to] = self.board[row_from][col_from]
        self.board[row_from][col_from] = ' '
```

