# This module defines the piece objects

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def __repr__(self):
        if self.color == 'B':
            return 'b' if not self.king else 'B'
        else:
            return 'w' if not self.king else 'W'

    def king_piece(self):
        self.king = True
